import React, { useState, useEffect } from 'react';
import axios from 'axios';

const SEMESTERS = [1, 2, 3, 4, 5, 6, 7, 8];

export default function FacultyFinalMarks() {
  const [finalMarks, setFinalMarks]   = useState([]);
  const [subjects,   setSubjects]     = useState([]);
  const [loading,    setLoading]      = useState(false);
  const [filter,     setFilter]       = useState({ semester: '', subjectId: '', search: '', section: '' });

  // Clear filters helper
  const clearFilters = () => setFilter({ semester: '', subjectId: '', search: '', section: '' });
  const hasFilters   = filter.semester || filter.subjectId || filter.search || filter.section;

  // Load subjects when semester changes
  useEffect(() => {
    if (!filter.semester) { setSubjects([]); return; }
    axios.get('/api/faculty/subjects', { params: { semester: filter.semester } })
      .then(res => setSubjects(res.data.subjects || []))
      .catch(() => setSubjects([]));
  }, [filter.semester]);

  // Load final marks (always fetch all, then filter client-side for speed)
  useEffect(() => {
    setLoading(true);
    const params = {};
    if (filter.semester) params.semester = filter.semester;
    axios.get('/api/faculty/final-marks', { params })
      .then(res => { setFinalMarks(res.data.finalMarks || []); setLoading(false); })
      .catch(() => setLoading(false));
  }, [filter.semester]); // only re-fetch when semester changes; subject/search/section are client-side

  // Client-side filters
  const displayed = finalMarks.filter(f => {
    if (filter.subjectId && f.subject?._id !== filter.subjectId) return false;
    if (filter.section   && f.student?.section !== filter.section) return false;
    if (filter.search) {
      const q = filter.search.toLowerCase();
      const nameMatch = f.student?.name?.toLowerCase().includes(q);
      const rollMatch = f.student?.rollNumber?.toLowerCase().includes(q);
      if (!nameMatch && !rollMatch) return false;
    }
    return true;
  });

  // Group by subject for table sections
  const grouped = {};
  displayed.forEach(f => {
    const key = f.subject?._id || 'unknown';
    if (!grouped[key]) grouped[key] = { subject: f.subject, semester: f.semester, entries: [] };
    grouped[key].entries.push(f);
  });

  // Unique sections from current data
  const uniqueSections = [...new Set(finalMarks.map(f => f.student?.section).filter(Boolean))].sort();

  // Calculate grade label
  const getGrade = (marks) => {
    if (marks >= 27) return { label: 'O',  color: '#7c3aed' };
    if (marks >= 24) return { label: 'A+', color: '#059669' };
    if (marks >= 21) return { label: 'A',  color: '#10b981' };
    if (marks >= 18) return { label: 'B+', color: '#1a56db' };
    if (marks >= 15) return { label: 'B',  color: '#3b82f6' };
    if (marks >= 12) return { label: 'C',  color: '#f59e0b' };
    return                  { label: 'F',  color: '#ef4444' };
  };

  return (
    <div>
      {/* Page header */}
      <div className="page-header">
        <div>
          <div className="page-title">🏆 Final View Marks</div>
          <div className="page-subtitle">
            Students where both Mid-1 and Mid-2 are approved by HOD — final marks auto-calculated
          </div>
        </div>
      </div>

      {/* Info banner */}
      <div className="info-box" style={{ marginBottom: 16 }}>
        📌 Final marks = <strong>80% of higher mid</strong> + <strong>20% of lower mid</strong>.
        Only shown when <strong>both</strong> Mid-1 &amp; Mid-2 are <strong>HOD-approved</strong>.
      </div>

      {/* Filters */}
      <div className="filter-bar">
        <select
          className="form-select" style={{ width: 160 }} value={filter.semester}
          onChange={e => setFilter({ ...filter, semester: e.target.value, subjectId: '' })}>
          <option value="">All Semesters</option>
          {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
        </select>

        <select
          className="form-select" style={{ width: 200 }} value={filter.subjectId}
          onChange={e => setFilter({ ...filter, subjectId: e.target.value })}
          disabled={!filter.semester}>
          <option value="">All Subjects</option>
          {subjects.map(s => <option key={s._id} value={s._id}>{s.name}</option>)}
        </select>

        <select
          className="form-select" style={{ width: 130 }} value={filter.section}
          onChange={e => setFilter({ ...filter, section: e.target.value })}>
          <option value="">All Sections</option>
          {uniqueSections.map(sec => <option key={sec} value={sec}>Section {sec}</option>)}
        </select>

        <input
          className="form-input-sm" style={{ width: 180 }}
          placeholder="🔍 Search name / roll no"
          value={filter.search}
          onChange={e => setFilter({ ...filter, search: e.target.value })}
        />

        {hasFilters && (
          <button className="btn btn-outline btn-sm" onClick={clearFilters}>✕ Clear Filters</button>
        )}

        <span className="text-muted" style={{ fontSize: 13 }}>
          {displayed.length} student{displayed.length !== 1 ? 's' : ''}
        </span>
      </div>

      {/* Content */}
      {loading ? (
        <div className="loading-screen" style={{ height: 200 }}>
          <div className="spinner"></div>
        </div>
      ) : displayed.length === 0 ? (
        <div className="card">
          <div className="empty-state">
            <div className="empty-icon">🏆</div>
            <div className="empty-text">No final marks available</div>
            <div className="empty-subtext">
              Final marks appear here once both Mid-1 and Mid-2 are approved by the HOD
            </div>
          </div>
        </div>
      ) : (
        Object.values(grouped).map(({ subject, semester, entries }) => {
          const avg = entries.length
            ? Math.round(entries.reduce((s, e) => s + e.finalMarks, 0) / entries.length)
            : 0;
          const passing = entries.filter(e => e.finalMarks >= 12).length;

          return (
            <div key={subject?._id} className="card mt-16">
              {/* Card header */}
              <div className="card-header">
                <div>
                  <span className="card-title">{subject?.name}</span>
                  <span style={{ marginLeft: 8, fontSize: 12, color: 'var(--text-muted)' }}>
                    {subject?.code}
                  </span>
                </div>
                <div className="gap-8">
                  <span className="badge badge-purple">Sem {semester}</span>
                  <span className="badge badge-gray">{entries.length} students</span>
                  <span className="badge badge-green">Avg: {avg}/30</span>
                  <span className="badge badge-blue">Pass: {passing}/{entries.length}</span>
                </div>
              </div>

              {/* Table */}
              <div className="table-wrapper">
                <table>
                  <thead>
                    <tr>
                      <th>#</th>
                      <th>Student</th>
                      <th>Roll Number</th>
                      <th>Section</th>
                      <th>Mid-1 /30</th>
                      <th>Mid-2 /30</th>
                      <th>Final /30</th>
                      <th>Grade</th>
                    </tr>
                  </thead>
                  <tbody>
                    {entries
                      .slice()
                      .sort((a, b) => (a.student?.rollNumber || '').localeCompare(b.student?.rollNumber || ''))
                      .map((f, i) => {
                        const grade = getGrade(f.finalMarks);
                        const isHigherMid1 = f.mid1Marks >= f.mid2Marks;
                        return (
                          <tr key={i}>
                            <td>{i + 1}</td>
                            <td className="fw-600">{f.student?.name}</td>
                            <td style={{ fontFamily: 'monospace', fontSize: 12 }}>
                              {f.student?.rollNumber}
                            </td>
                            <td>{f.student?.section || '—'}</td>
                            <td style={{ color: isHigherMid1 ? '#7c3aed' : undefined }}>
                              {f.mid1Marks}
                              {isHigherMid1 && (
                                <span title="Higher mid (80% weight)" style={{ marginLeft: 4, fontSize: 10 }}>★</span>
                              )}
                            </td>
                            <td style={{ color: !isHigherMid1 ? '#7c3aed' : undefined }}>
                              {f.mid2Marks}
                              {!isHigherMid1 && (
                                <span title="Higher mid (80% weight)" style={{ marginLeft: 4, fontSize: 10 }}>★</span>
                              )}
                            </td>
                            <td className="fw-600" style={{ color: '#7c3aed', fontSize: 15 }}>
                              {f.finalMarks}/30
                            </td>
                            <td>
                              <span
                                className="badge"
                                style={{ background: grade.color, color: '#fff', minWidth: 32, textAlign: 'center' }}>
                                {grade.label}
                              </span>
                            </td>
                          </tr>
                        );
                      })}
                  </tbody>
                </table>
              </div>

              {/* Summary footer */}
              <div style={{
                padding: '10px 20px',
                borderTop: '1px solid var(--border)',
                display: 'flex',
                gap: 24,
                fontSize: 12,
                color: 'var(--text-muted)',
                background: '#f8fafc',
                flexWrap: 'wrap'
              }}>
                <span>★ = Higher mid (80% weight applied)</span>
                <span>Formula: 0.8 × higher + 0.2 × lower</span>
                <span style={{ marginLeft: 'auto' }}>
                  Pass rate: <strong style={{ color: '#10b981' }}>{passing}</strong> / {entries.length}
                </span>
              </div>
            </div>
          );
        })
      )}
    </div>
  );
}
